editmore_vertUserCan you greatly enhance and improve the overall quality and feature set?: <!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Real-time Audio Quantizer</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet">
    <style>
        :root {
            --bg-color: #121212;
            --surface-color: #1e1e1e;
            --primary-color: #bb86fc;
            --secondary-color: #03dac6;
            --text-color: #e0e0e0;
            --pad-color: #333333;
            --pad-active-color: var(--primary-color);
            --pad-playing-color: var(--secondary-color);
            --pad-recording-color: #ff4141;
            --step-off-color: #2a2a2a;
            --step-on-color: var(--primary-color);
            --current-step-color: #ffffff;
        }

        body {
            font-family: 'Inter', sans-serif;
            background-color: var(--bg-color);
            color: var(--text-color);
        }

        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }

        .pad {
            transition: all 0.05s ease-in-out;
            border: 2px solid var(--surface-color);
        }
        .pad.selected {
            box-shadow: 0 0 15px var(--pad-active-color), inset 0 0 10px rgba(187, 134, 252, 0.3);
            border-color: var(--pad-active-color);
            transform: scale(1.03);
        }
        .pad.playing {
            animation: pulse-play 0.2s 1;
        }
        .pad.recording {
            animation: pulse-record 0.5s infinite alternate;
        }

        @keyframes pulse-play {
            0% { background-color: var(--pad-playing-color); transform: scale(1.05); }
            100% { background-color: var(--pad-color); transform: scale(1); }
        }

        @keyframes pulse-record {
            from { background-color: var(--pad-recording-color); box-shadow: 0 0 20px #ff4141; }
            to { background-color: var(--surface-color); box-shadow: none; }
        }

        .step {
            transition: background-color 0.1s;
        }
        .step.active {
            background-color: var(--step-on-color);
            box-shadow: 0 0 5px var(--step-on-color);
        }
        .step.current {
            border: 2px solid var(--current-step-color);
            transform: scale(1.2);
        }

        input[type="range"] {
            -webkit-appearance: none;
            appearance: none;
            width: 100%;
            height: 8px;
            background: var(--surface-color);
            border-radius: 5px;
            outline: none;
            transition: opacity .2s;
        }
        input[type="range"]::-webkit-slider-thumb {
            -webkit-appearance: none;
            appearance: none;
            width: 18px;
            height: 18px;
            background: var(--primary-color);
            cursor: pointer;
            border-radius: 50%;
            border: 2px solid var(--bg-color);
        }
        input[type="range"]::-moz-range-thumb {
            width: 18px;
            height: 18px;
            background: var(--primary-color);
            cursor: pointer;
            border-radius: 50%;
            border: 2px solid var(--bg-color);
        }

        .ai-assistant-window {
            transition: transform 0.3s ease-in-out;
        }

        .loader {
            border: 4px solid #f3f3f3;
            border-top: 4px solid var(--primary-color);
            border-radius: 50%;
            width: 40px;
            height: 40px;
            animation: spin 1s linear infinite;
        }

        @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
        }

        .tooltip {
            position: relative;
            display: inline-block;
        }

        .tooltip .tooltiptext {
            visibility: hidden;
            width: 140px;
            background-color: #555;
            color: #fff;
            text-align: center;
            border-radius: 6px;
            padding: 5px;
            position: absolute;
            z-index: 1;
            bottom: 125%;
            left: 50%;
            margin-left: -70px;
            opacity: 0;
            transition: opacity 0.3s;
        }

        .tooltip:hover .tooltiptext {
            visibility: visible;
            opacity: 1;
        }

    </style>
</head>
<body class="w-screen min-h-screen flex flex-col items-center justify-center p-2 lg:p-4 text-xs lg:text-sm">

    <!-- Main Application Wrapper -->
    <div id="app-container" class="w-full h-full bg-black rounded-xl shadow-2xl flex flex-col lg:flex-row gap-4 p-4">

        <!-- Left Column: Sampler, Sequencer, Transport -->
        <div class="flex flex-col gap-4 w-full lg:w-2/3">
            <!-- Transport Controls -->
            <div class="bg-surface-color rounded-lg p-3 flex items-center justify-between gap-4">
                <div class="flex items-center gap-2">
                    <button id="play-pause-btn" class="w-24 bg-primary-color text-black font-bold py-2 px-4 rounded-md hover:bg-opacity-80 transition">Play</button>
                    <button id="arm-record-btn" class="w-24 bg-gray-500 text-white font-bold py-2 px-4 rounded-md hover:bg-opacity-80 transition">Arm Record</button>
                    <button id="generate-kit-btn" class="bg-green-500 text-black font-bold py-2 px-4 rounded-md hover:bg-opacity-80 transition whitespace-nowrap">✨ Gen Kit</button>
                </div>
                <div class="flex items-center gap-2 w-1/3">
                    <label for="tempo-slider" class="font-medium">Tempo</label>
                    <input type="range" id="tempo-slider" min="40" max="240" value="120" class="w-full">
                    <span id="tempo-display" class="font-mono w-12 text-center">120</span>
                </div>
                 <!-- Set Selector -->
                <div class="flex items-center gap-1 bg-bg-color p-1 rounded-md">
                     <span class="font-medium mr-2 ml-1">SET:</span>
                    <div id="set-selector" class="flex items-center gap-1"></div>
                </div>
                <button id="tts-toggle-btn" class="p-2 bg-gray-700 rounded-full hover:bg-gray-600 transition flex-shrink-0">
                    <svg id="tts-icon-on" xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="text-secondary-color hidden"><path d="M11 5L6 9H2v6h4l5 4V5z"></path><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
                    <svg id="tts-icon-off" xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="text-gray-500"><line x1="1" y1="1" x2="23" y2="23"></line><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path><path d="M10.74 3.93a2.5 2.5 0 0 1-2.74 2.55M6 15H2v-6h4"></path><path d="M11 5v.09"></path></svg>
                 </button>
            </div>

            <!-- 16 Pad Sampler Grid -->
            <div id="pad-grid" class="grid grid-cols-4 gap-2 lg:gap-4 flex-grow aspect-square lg:aspect-auto">
                <!-- Pads will be generated here -->
            </div>

            <!-- 16-Step Sequencer -->
            <div class="bg-surface-color rounded-lg p-3">
                <div class="flex justify-between items-center mb-2">
                    <h3 class="text-sm font-bold">SEQUENCER - PAD <span id="sequencer-pad-label">1</span></h3>
                    <button id="evolve-pattern-btn" class="bg-purple-600 text-white text-xs font-bold py-1 px-3 rounded-md hover:bg-opacity-80 transition">✨ Evolve</button>
                </div>
                <div id="sequencer-grid" class="grid grid-cols-16 gap-1 lg:gap-2">
                    <!-- Sequencer steps will be generated here -->
                </div>
            </div>
        </div>

        <!-- Center Column: Video & Waveform -->
        <div class="flex flex-col gap-4 w-full lg:w-1/3 h-full">
            <div class="bg-surface-color rounded-lg p-3 flex flex-col flex-grow relative">
                <h3 class="text-sm font-bold mb-2">VISUALS</h3>
                <div id="video-display" class="w-full flex-grow bg-black rounded-md flex items-center justify-center overflow-hidden">
                    <span class="text-gray-500">Visuals for triggered pad appear here</span>
                </div>
                 <div id="visual-loader" class="absolute inset-0 bg-black bg-opacity-70 flex-col items-center justify-center hidden">
                    <div class="loader"></div>
                    <p class="mt-4 font-semibold">Generating Visuals...</p>
                </div>
            </div>
            <div class="bg-surface-color rounded-lg p-3 flex flex-col h-1/4">
                 <h3 class="text-sm font-bold mb-2">LIVE INPUT</h3>
                <canvas id="waveform-canvas" class="w-full h-full bg-black rounded-md"></canvas>
            </div>
        </div>

        <!-- Right Column (Sidebar): Pad Settings -->
        <div id="settings-sidebar" class="bg-surface-color rounded-lg p-4 w-full lg:w-1/3 flex flex-col gap-4 overflow-y-auto no-scrollbar">
            <h2 class="text-lg font-bold text-center border-b border-gray-700 pb-2">PAD <span id="selected-pad-label">1</span> SETTINGS</h2>

            <!-- Sound Shaping -->
            <div class="bg-bg-color rounded-lg p-3">
                <h3 class="font-semibold mb-2">Sound Shaping</h3>
                <div class="grid grid-cols-2 gap-x-4 gap-y-2 text-sm">
                    <!-- Gain -->
                    <label for="gain-slider">Gain</label><span id="gain-value" class="font-mono text-right">1.00</span>
                    <input type="range" id="gain-slider" min="0" max="2" value="1" step="0.01" class="col-span-2">
                    <!-- Pan -->
                    <label for="pan-slider">Pan</label><span id="pan-value" class="font-mono text-right">0.00</span>
                    <input type="range" id="pan-slider" min="-1" max="1" value="0" step="0.01" class="col-span-2">
                    <!-- Pitch -->
                    <label for="pitch-slider">Pitch</label><span id="pitch-value" class="font-mono text-right">0 st</span>
                    <input type="range" id="pitch-slider" min="-24" max="24" value="0" step="1" class="col-span-2">
                    <!-- Filter Cutoff -->
                    <label for="cutoff-slider">Filter Cutoff</label><span id="cutoff-value" class="font-mono text-right">20000 Hz</span>
                    <input type="range" id="cutoff-slider" min="20" max="20000" value="20000" step="1" class="col-span-2">
                    <!-- Filter Resonance -->
                    <label for="resonance-slider">Filter Res</label><span id="resonance-value" class="font-mono text-right">0.0</span>
                    <input type="range" id="resonance-slider" min="0" max="20" value="0" step="0.1" class="col-span-2">
                     <!-- Attack -->
                    <label for="attack-slider">Attack</label><span id="attack-value" class="font-mono text-right">0.01 s</span>
                    <input type="range" id="attack-slider" min="0.01" max="2" value="0.01" step="0.01" class="col-span-2">
                     <!-- Release -->
                    <label for="release-slider">Release</label><span id="release-value" class="font-mono text-right">0.50 s</span>
                    <input type="range" id="release-slider" min="0.01" max="4" value="0.5" step="0.01" class="col-span-2">
                    <!-- Loop Toggle -->
                    <label for="loop-toggle" class="col-span-2 flex items-center justify-between">
                        <span>Loop Sample</span>
                        <input type="checkbox" id="loop-toggle" class="form-checkbox h-5 w-5 text-primary-color bg-gray-800 border-gray-600 rounded focus:ring-primary-color">
                    </label>
                </div>
            </div>

            <!-- AI Features -->
            <div class="bg-bg-color rounded-lg p-3">
                 <h3 class="font-semibold mb-2">AI Generation</h3>
                 <!-- AI Video/Image Generation -->
                 <div class="flex flex-col gap-2">
                     <label for="video-prompt-input" class="text-sm">Visual Prompt</label>
                     <div class="flex gap-2">
                        <input type="text" id="video-prompt-input" placeholder="e.g., a cat DJing in space" class="bg-surface-color border border-gray-600 rounded-md p-2 w-full focus:outline-none focus:ring-2 focus:ring-primary-color">
                        <button id="generate-video-btn" class="bg-secondary-color text-black font-bold px-3 rounded-md hover:bg-opacity-80 transition">Gen</button>
                    </div>
                 </div>
                 <!-- Randomizers -->
                 <div class="flex gap-2 mt-4">
                     <button id="randomize-sound-btn" class="w-full bg-primary-color bg-opacity-50 py-2 rounded-md hover:bg-opacity-70 transition">Randomize Sound</button>
                     <button id="randomize-pattern-btn" class="w-full bg-primary-color bg-opacity-50 py-2 rounded-md hover:bg-opacity-70 transition">Randomize Pattern</button>
                 </div>
            </div>

            <!-- Set Assignment -->
            <div class="bg-bg-color rounded-lg p-3">
                 <h3 class="font-semibold mb-2">Pad Assignment</h3>
                 <div class="flex flex-col gap-2">
                     <label for="pad-set-select" class="text-sm">Assign Pad to Set</label>
                     <select id="pad-set-select" class="bg-surface-color border border-gray-600 rounded-md p-2 w-full focus:outline-none focus:ring-2 focus:ring-primary-color">
                         <!-- Options generated by JS -->
                     </select>
                 </div>
            </div>

        </div>

    </div>

    <!-- AI Assistant Chat Window -->
    <div id="ai-assistant-window" class="ai-assistant-window fixed bottom-4 right-4 bg-surface-color rounded-xl shadow-2xl w-96 transform translate-y-full transition-transform duration-300 ease-in-out">
        <button id="ai-assistant-toggle" class="absolute -top-10 right-0 bg-primary-color text-black font-bold py-2 px-4 rounded-t-lg">AI Assistant</button>
        <div class="p-4 h-full flex flex-col">
            <h3 class="font-bold text-center text-lg mb-2">AI Assistant</h3>
            <div id="ai-chat-box" class="flex-grow bg-bg-color rounded-md p-2 overflow-y-auto mb-2 h-64 no-scrollbar">
                <!-- Chat messages will appear here -->
                <div class="text-gray-400 p-2">Describe a sound or a rhythm for the selected pad (e.g., "make a deep kick drum" or "four on the floor beat").</div>
            </div>
            <div id="ai-loader" class="text-center my-2 hidden">
                <p>AI is thinking...</p>
            </div>
            <div class="flex gap-2">
                <input type="text" id="ai-prompt-input" placeholder="Type your request..." class="bg-bg-color border border-gray-600 rounded-full p-2 w-full focus:outline-none focus:ring-2 focus:ring-primary-color px-4">
                <button id="send-ai-btn" class="bg-secondary-color text-black font-bold px-5 rounded-full hover:bg-opacity-80 transition">Send</button>
            </div>
        </div>
    </div>

    <!-- Startup Modal -->
    <div id="startup-modal" class="fixed inset-0 bg-black bg-opacity-80 flex items-center justify-center z-[60]">
        <div class="bg-surface-color p-8 rounded-lg text-center">
            <h1 class="text-2xl font-bold mb-4">Real-time Audio Quantizer</h1>
            <p class="mb-6">Click Start to enable audio.</p>
            <button id="start-btn" class="bg-primary-color text-black font-bold py-3 px-8 rounded-md text-lg hover:bg-opacity-80 transition">Start</button>
        </div>
    </div>

    <!-- Toast Notification -->
    <div id="toast-notification" class="fixed bottom-5 left-1/2 -translate-x-1/2 bg-secondary-color text-black font-bold py-3 px-6 rounded-lg shadow-lg text-center z-[70] opacity-0 transition-opacity duration-300 pointer-events-none">
        <p id="toast-text"></p>
    </div>

    <!-- Full Screen Loader -->
    <div id="full-screen-loader" class="fixed inset-0 bg-black bg-opacity-75 flex-col items-center justify-center z-50 hidden">
        <div class="loader"></div>
        <p id="loader-text" class="mt-4 font-semibold text-lg">Generating...</p>
    </div>


<script>
document.addEventListener('DOMContentLoaded', () => {

    // --- DOM ELEMENT REFERENCES --- //
    const padGrid = document.getElementById('pad-grid');
    const sequencerGrid = document.getElementById('sequencer-grid');
    const playPauseBtn = document.getElementById('play-pause-btn');
    const armRecordBtn = document.getElementById('arm-record-btn');
    const tempoSlider = document.getElementById('tempo-slider');
    const tempoDisplay = document.getElementById('tempo-display');
    const sequencerPadLabel = document.getElementById('sequencer-pad-label');
    const selectedPadLabel = document.getElementById('selected-pad-label');
    const gainSlider = document.getElementById('gain-slider');
    const gainValue = document.getElementById('gain-value');
    const panSlider = document.getElementById('pan-slider');
    const panValue = document.getElementById('pan-value');
    const pitchSlider = document.getElementById('pitch-slider');
    const pitchValue = document.getElementById('pitch-value');
    const cutoffSlider = document.getElementById('cutoff-slider');
    const cutoffValue = document.getElementById('cutoff-value');
    const resonanceSlider = document.getElementById('resonance-slider');
    const resonanceValue = document.getElementById('resonance-value');
    const attackSlider = document.getElementById('attack-slider');
    const attackValue = document.getElementById('attack-value');
    const releaseSlider = document.getElementById('release-slider');
    const releaseValue = document.getElementById('release-value');
    const loopToggle = document.getElementById('loop-toggle');
    const setSelector = document.getElementById('set-selector');
    const padSetSelect = document.getElementById('pad-set-select');
    const startupModal = document.getElementById('startup-modal');
    const startBtn = document.getElementById('start-btn');
    const toastNotification = document.getElementById('toast-notification');
    const toastText = document.getElementById('toast-text');
    const waveformCanvas = document.getElementById('waveform-canvas');
    const videoDisplay = document.getElementById('video-display');
    const videoPromptInput = document.getElementById('video-prompt-input');
    const generateVideoBtn = document.getElementById('generate-video-btn');
    const visualLoader = document.getElementById('visual-loader');
    const randomizeSoundBtn = document.getElementById('randomize-sound-btn');
    const randomizePatternBtn = document.getElementById('randomize-pattern-btn');
    const aiAssistantWindow = document.getElementById('ai-assistant-window');
    const aiAssistantToggle = document.getElementById('ai-assistant-toggle');
    const aiChatBox = document.getElementById('ai-chat-box');
    const aiPromptInput = document.getElementById('ai-prompt-input');
    const sendAiBtn = document.getElementById('send-ai-btn');
    const aiLoader = document.getElementById('ai-loader');
    const generateKitBtn = document.getElementById('generate-kit-btn');
    const evolvePatternBtn = document.getElementById('evolve-pattern-btn');
    const ttsToggleBtn = document.getElementById('tts-toggle-btn');
    const ttsIconOn = document.getElementById('tts-icon-on');
    const ttsIconOff = document.getElementById('tts-icon-off');
    const fullScreenLoader = document.getElementById('full-screen-loader');
    const loaderText = document.getElementById('loader-text');


    // --- AUDIO & APP STATE --- //
    let audioContext;
    let pads = [];
    let sets = [];
    const NUM_PADS = 16;
    const NUM_STEPS = 16;
    const NUM_SETS = 8;

    let isPlaying = false;
    let isArmed = false;
    let tempo = 120;
    let currentStep = 0;
    let selectedPadIndex = 0;
    let activeSetIndex = 0;
    let nextStepTime = 0.0;
    let scheduleAheadTime = 0.1; // seconds
    let timerID;
    let isTtsEnabled = false;
    let baseSample = null;
    let scheduledSources = []; // To keep track of sounds scheduled to play
    let toastTimer;

    let micStream;
    let mediaRecorder;
    let analyser;
    let waveformData;
    let waveformCtx = waveformCanvas.getContext('2d');

    // --- INITIALIZATION --- //

    function init() {
        // Create Sets
        const setColors = ['#bb86fc', '#03dac6', '#cf6679', '#ffde03', '#03a9f4', '#4caf50', '#ff9800', '#9c27b0'];
        for (let i = 0; i < NUM_SETS; i++) {
            sets.push({
                id: i,
                name: `Set ${i + 1}`,
                color: setColors[i],
            });
        }

        // Create Pads
        for (let i = 0; i < NUM_PADS; i++) {
            pads.push({
                id: i,
                sample: null,
                set: 0, 
                gain: 1.0,
                pan: 0.0,
                pitch: 0,
                filterCutoff: 20000,
                filterResonance: 0,
                attack: 0.01,
                release: 0.5,
                loop: false,
                pattern: Array(NUM_STEPS).fill(false),
                visualUrl: null,
                visualPrompt: ""
            });
        }

        createUI();
        updateUI();
        startupModal.style.display = 'flex';
    }

    async function startApp() {
        audioContext = new (window.AudioContext || window.webkitAudioContext)();
        createBaseSample();
        await setupMicrophone();
        drawWaveform();
        startupModal.style.display = 'none';
    }

    async function setupMicrophone() {
        try {
            micStream = await navigator.mediaDevices.getUserMedia({ audio: true });
            const source = audioContext.createMediaStreamSource(micStream);
            analyser = audioContext.createAnalyser();
            analyser.fftSize = 2048;
            source.connect(analyser);
            waveformData = new Uint8Array(analyser.frequencyBinCount);
            mediaRecorder = new MediaRecorder(micStream);

            mediaRecorder.ondataavailable = (event) => {
                if(event.data.size > 0) {
                    const padIndexToRecord = (currentStep - 1 + NUM_STEPS) % NUM_STEPS;
                    if (pads[padIndexToRecord].set === activeSetIndex) {
                        const reader = new FileReader();
                        reader.onload = () => {
                            audioContext.decodeAudioData(reader.result, (buffer) => {
                                pads[padIndexToRecord].sample = buffer;
                                showMessage(`Sample recorded to Pad ${padIndexToRecord + 1}`);
                                const padEl = document.querySelector(`.pad[data-id='${padIndexToRecord}']`);
                                if (padEl) padEl.style.backgroundColor = sets[pads[padIndexToRecord].set].color;
                            });
                        };
                        reader.readAsArrayBuffer(event.data);
                    }
                }
            };

        } catch (err) {
            console.error('Error accessing microphone:', err);
            showMessage('Could not access microphone. Recording disabled.');
        }
    }


    // --- UI CREATION & UPDATES --- //

    function createBaseSample() {
        if (!audioContext || baseSample) return;
        const frameCount = audioContext.sampleRate * 0.1; // 100ms
        const buffer = audioContext.createBuffer(1, frameCount, audioContext.sampleRate);
        const data = buffer.getChannelData(0);
        // A simple decaying sine wave as a base for synthesis
        for (let i = 0; i < frameCount; i++) {
            data[i] = Math.sin(i / frameCount * Math.PI * 8) * Math.exp(-i / frameCount * 8);
        }
        baseSample = buffer;
    }

    function createUI() {
        // Pads
        padGrid.innerHTML = '';
        for (let i = 0; i < NUM_PADS; i++) {
            const padEl = document.createElement('button');
            padEl.className = 'pad rounded-lg aspect-square flex items-center justify-center font-bold text-xl';
            padEl.dataset.id = i;
            padEl.textContent = i + 1;
            padGrid.appendChild(padEl);
        }

        // Sequencer
        sequencerGrid.innerHTML = '';
        for (let i = 0; i < NUM_STEPS; i++) {
            const stepEl = document.createElement('div');
            stepEl.className = 'step rounded-md aspect-square';
            stepEl.dataset.id = i;
            sequencerGrid.appendChild(stepEl);
        }

        // Set Selector
        setSelector.innerHTML = '';
        sets.forEach(set => {
            const setBtn = document.createElement('button');
            setBtn.className = 'w-6 h-6 rounded-md border-2';
            setBtn.dataset.id = set.id;
            setBtn.style.backgroundColor = set.color;
            setSelector.appendChild(setBtn);
        });

        // Set Assignment Dropdown
        padSetSelect.innerHTML = '';
        sets.forEach(set => {
            const option = document.createElement('option');
            option.value = set.id;
            option.textContent = set.name;
            padSetSelect.appendChild(option);
        });
    }

    function updateUI() {
        updatePads();
        updateSequencer();
        updateSidebar();
        updateSetSelector();
    }

    function updatePads() {
        const padElements = document.querySelectorAll('.pad');
        padElements.forEach((padEl, i) => {
            const padData = pads[i];
            padEl.classList.toggle('selected', i === selectedPadIndex);

            if (padData.sample) {
                padEl.style.backgroundColor = sets[padData.set].color;
                padEl.style.opacity = '1';
            } else {
                 padEl.style.backgroundColor = 'var(--pad-color)';
                 padEl.style.opacity = '0.5';
            }
            // Show only pads of the active set
            padEl.style.visibility = padData.set === activeSetIndex ? 'visible' : 'hidden';
        });
    }

    function updateSequencer() {
