    async function getAISoundDesign(prompt, padIndex, silent = false) {
        const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-05-20:generateContent?key=${apiKey}`;
        const systemPrompt = "You are a sound design assistant for a 16-pad sampler. Based on the user's text description, generate the parameters for the sound. Respond ONLY with a valid JSON object matching the provided schema. Pitch is in semitones from -24 to 24. Filter cutoff is in Hz from 20 to 20000. Filter resonance is from 0.0 to 20.0. Attack and Release are in seconds from 0.01 to 4.0.";
        const payload = {
            systemInstruction: { parts: [{ text: systemPrompt }] },
            contents: [{ parts: [{ text: prompt }] }],
            generationConfig: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: "OBJECT",
                    properties: {
                        pitch: { type: "NUMBER", description: "Pitch shift in semitones." },
                        filterCutoff: { type: "NUMBER", description: "Low-pass filter cutoff in Hz." },
                        filterResonance: { type: "NUMBER", description: "Filter resonance (Q factor)." },
                        attack: { type: "NUMBER", description: "Envelope attack time in seconds." },
                        release: { type: "NUMBER", description: "Envelope release time in seconds." }
                    },
                    required: ["pitch", "filterCutoff", "filterResonance", "attack", "release"]
                }
            }
        };

        const response = await fetch(apiUrl, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
        });
        if(!response.ok) throw new Error(`API Error: ${response.statusText}`);

        const result = await response.json();
        const jsonText = result.candidates[0].content.parts[0].text;
        const params = JSON.parse(jsonText);

        const pad = pads[padIndex];
        pad.sample = baseSample; // Assign a base sound source to be shaped
        pad.pitch = Math.max(-24, Math.min(24, Math.round(params.pitch)));
        pad.filterCutoff = Math.max(20, Math.min(20000, Math.round(params.filterCutoff)));
        pad.filterResonance = Math.max(0, Math.min(20, parseFloat(params.filterResonance.toFixed(1))));
        pad.attack = Math.max(0.01, Math.min(2, parseFloat(params.attack.toFixed(2))));
        pad.release = Math.max(0.01, Math.min(4, parseFloat(params.release.toFixed(2))));

        if (!silent) {
            addChatMessage('assistant', `OK, I've created a sound for you on Pad ${padIndex + 1}.`);
            updateSidebar();
        }
    }

    async function getAIPattern(prompt, padIndex, silent = false) {
        const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-05-20:generateContent?key=${apiKey}`;
        const systemPrompt = "You are a rhythm programming assistant. The user will describe a beat or pattern. Generate a 16-step sequencer pattern as a JSON object. The object should have one key, 'pattern', which is an array of 16 booleans. `true` means the step is on, `false` means it is off. Respond ONLY with the valid JSON object.";
        const payload = {
            systemInstruction: { parts: [{ text: systemPrompt }] },
            contents: [{ parts: [{ text: prompt }] }],
            generationConfig: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: "OBJECT",
                    properties: {
                        pattern: { type: "ARRAY", items: { type: "BOOLEAN" }}
                    },
                    required: ["pattern"]
                }
            }
        };

        const response = await fetch(apiUrl, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
