            stepEl.className = 'step rounded-md aspect-square';
            stepEl.dataset.id = i;
            sequencerGrid.appendChild(stepEl);
        }

        setSelector.innerHTML = '';
        sets.forEach(set => {
            const setBtn = document.createElement('button');
            setBtn.className = 'w-6 h-6 rounded-md border-2 transition-transform';
            setBtn.dataset.id = set.id;
            setBtn.style.backgroundColor = set.color;
            setSelector.appendChild(setBtn);
        });

        padSetSelect.innerHTML = '';
        sets.forEach(set => {
            const option = document.createElement('option');
            option.value = set.id;
            option.textContent = set.name;
            padSetSelect.appendChild(option);
        });
    }

    function updateUI() {
        updatePads();
        updateSequencer();
        updateSidebar();
        updateSetSelector();
    }

    function updatePads() {
        document.querySelectorAll('.pad').forEach((padEl, i) => {
            const padData = pads[i];
            padEl.classList.toggle('selected', i === selectedPadIndex);
            padEl.classList.toggle('pad-has-sample', !!padData.sample);

            if (padData.sample) {
                padEl.style.backgroundColor = sets[padData.set].color;
                padEl.style.opacity = '1';
            } else {
                 padEl.style.backgroundColor = 'var(--pad-color)';
                 padEl.style.opacity = '0.5';
            }
            padEl.style.visibility = padData.set === activeSetIndex ? 'visible' : 'hidden';
        });
    }

    function updateSequencer() {
        sequencerPadLabel.textContent = selectedPadIndex + 1;
        const pattern = pads[selectedPadIndex].pattern;
        document.querySelectorAll('.step').forEach((stepEl, i) => {
            stepEl.classList.toggle('active', pattern[i]);
            stepEl.classList.remove('current');
        });
         if (isPlaying) {
            const currentStepEl = sequencerGrid.children[currentStep];
            if(currentStepEl) currentStepEl.classList.add('current');
        }
    }

    function updateSidebar() {
        const pad = pads[selectedPadIndex];
        selectedPadLabel.textContent = selectedPadIndex + 1;
        sampleNameEl.textContent = pad.sampleName;

        const updateSlider = (slider, display, value, text) => {
            slider.value = value;
            display.textContent = text;
        };

        updateSlider(gainSlider, gainValue, pad.gain, parseFloat(pad.gain).toFixed(2));
        updateSlider(panSlider, panValue, pad.pan, parseFloat(pad.pan).toFixed(2));
        updateSlider(pitchSlider, pitchValue, pad.pitch, `${pad.pitch} st`);
        updateSlider(cutoffSlider, cutoffValue, pad.filterCutoff, `${Math.round(pad.filterCutoff/1000)}k Hz`);
        updateSlider(resonanceSlider, resonanceValue, pad.filterResonance, parseFloat(pad.filterResonance).toFixed(1));
        updateSlider(attackSlider, attackValue, pad.attack, `${parseFloat(pad.attack).toFixed(2)} s`);
        updateSlider(releaseSlider, releaseValue, pad.release, `${parseFloat(pad.release).toFixed(2)} s`);

        loopToggle.checked = pad.loop;
        padSetSelect.value = pad.set;
        videoPromptInput.value = pad.visualPrompt;
        drawEnvelope();
    }

    function updateSetSelector() {
        document.querySelectorAll('#set-selector button').forEach(btn => {
            const is_active = parseInt(btn.dataset.id) === activeSetIndex;
            btn.style.borderColor = is_active ? 'white' : 'transparent';
            btn.style.transform = is_active ? 'scale(1.1)' : 'scale(1)';
        });
    }

    function drawWaveform() {
        requestAnimationFrame(drawWaveform);
        if (!analyser) return;

        analyser.getByteTimeDomainData(waveformData);
        waveformCtx.fillStyle = '#000000';
        waveformCtx.fillRect(0, 0, waveformCanvas.width, waveformCanvas.height);
        waveformCtx.lineWidth = 2;
        waveformCtx.strokeStyle = 'rgb(3, 218, 198)';
        waveformCtx.beginPath();

        const sliceWidth = waveformCanvas.width * 1.0 / analyser.frequencyBinCount;
        let x = 0;
        for (let i = 0; i < analyser.frequencyBinCount; i++) {
            const v = waveformData[i] / 128.0;
            const y = v * waveformCanvas.height / 2;
            if (i === 0) waveformCtx.moveTo(x, y); else waveformCtx.lineTo(x, y);
            x += sliceWidth;
        }
        waveformCtx.lineTo(waveformCanvas.width, waveformCanvas.height / 2);
        waveformCtx.stroke();
    }

    function drawEnvelope() {
        const pad = pads[selectedPadIndex];
        const w = envelopeCanvas.width;
        const h = envelopeCanvas.height;
        const totalDuration = pad.attack + pad.release;

        envelopeCtx.clearRect(0, 0, w, h);
        envelopeCtx.strokeStyle = 'var(--secondary-color)';
        envelopeCtx.lineWidth = 2;
        envelopeCtx.beginPath();
        envelopeCtx.moveTo(0, h);

        // Attack phase
        const attackX = (pad.attack / totalDuration) * w;
        envelopeCtx.lineTo(attackX, 0);

        // Release phase
        envelopeCtx.lineTo(w, h);

        envelopeCtx.stroke();
    }

    // --- SEQUENCER & PLAYBACK --- //

    function togglePlayback() {
        if (!audioContext) startApp();
        isPlaying = !isPlaying;
        if (isPlaying) {
            currentStep = -1;
            nextStepTime = audioContext.currentTime;
            scheduler();
            playPauseBtn.textContent = 'Pause';
            playPauseBtn.style.backgroundColor = 'var(--secondary-color)';
        } else {
            window.clearTimeout(timerID);
            scheduledSources.forEach(source => { try { source.stop(); } catch(e) {} });
            scheduledSources = [];
            playPauseBtn.textContent = 'Play';
            playPauseBtn.style.backgroundColor = 'var(--primary-color)';
            const currentStepEl = sequencerGrid.querySelector('.current');
            if (currentStepEl) currentStepEl.classList.remove('current');
        }
    }

    function scheduler() {
        while (nextStepTime < audioContext.currentTime + scheduleAheadTime) {
            scheduleStep(currentStep, nextStepTime);
            nextStep();
        }
        timerID = window.setTimeout(scheduler, 25.0);
        requestAnimationFrame(updateSequencer);
    }

    function nextStep() {
        const secondsPerBeat = 60.0 / tempo;
        const stepDuration = 0.25 * secondsPerBeat; // 16th note

        // Apply swing
        const isOddStep = currentStep % 2 !== 0;
        const swingDelay = isOddStep ? (stepDuration * (swing / 100)) : 0;

        nextStepTime += stepDuration;
        currentStep = (currentStep + 1) % NUM_STEPS;
    }

    function scheduleStep(step, time) {
        if (step < 0) return;
        const stepDuration = (60 / tempo) / 4;
        const swingDelay = ((step +1) % 2 !== 0) ? (stepDuration * (swing / 100)) : 0;

        pads.forEach((pad, padIndex) => {
            if (pad.pattern[step] && pad.sample && pad.set === activeSetIndex) {
                playSound(padIndex, time + swingDelay);
                const padEl = document.querySelector(`.pad[data-id='${padIndex}']`);
                if(padEl) {
                    padEl.classList.add('playing');
                    setTimeout(() => padEl.classList.remove('playing'), 200);
                }
            }
        });

        if(isArmed && mediaRecorder && mediaRecorder.state === 'inactive') {
            const padToRecord = step;
            if (pads[padToRecord].set === activeSetIndex) {
                const padEl = document.querySelector(`.pad[data-id='${padToRecord}']`);
                if(padEl) padEl.classList.add('recording');
                mediaRecorder.start();
                setTimeout(() => {
                    if (mediaRecorder.state === 'recording') {
                        mediaRecorder.stop();
                        if(padEl) padEl.classList.remove('recording');
                    }
                }, stepDuration * 1000);
            }
        }
    }

    function playSound(padIndex, time = 0) {
        const pad = pads[padIndex];
        if (!pad.sample || !audioContext) return;

        const source = audioContext.createBufferSource();
        source.onended = () => {
            const index = scheduledSources.indexOf(source);
            if (index > -1) scheduledSources.splice(index, 1);
        };

        source.buffer = pad.sample;
        source.loop = pad.loop;
        source.playbackRate.value = Math.pow(2, pad.pitch / 12);

        const gainNode = audioContext.createGain();
        const pannerNode = audioContext.createStereoPanner();
        pannerNode.pan.value = pad.pan;
        const filterNode = audioContext.createBiquadFilter();
        filterNode.type = 'lowpass';
        filterNode.frequency.value = pad.filterCutoff;
        filterNode.Q.value = pad.filterResonance;

        const now = time > 0 ? time : audioContext.currentTime;
        gainNode.gain.setValueAtTime(0, now);
        gainNode.gain.linearRampToValueAtTime(pad.gain, now + pad.attack);
        gainNode.gain.linearRampToValueAtTime(0, now + pad.attack + pad.release);

        source.connect(filterNode).connect(pannerNode).connect(gainNode).connect(audioContext.destination);

        scheduledSources.push(source);
        source.start(now);

        if(pad.visualUrl) {
            videoDisplay.innerHTML = `<img src="${pad.visualUrl}" class="w-full h-full object-cover" alt="${pad.visualPrompt}">`;
        }
    }

