    // --- SAMPLE & PROJECT MANAGEMENT --- //

    async function handleSampleLoad(event) {
        const file = event.target.files[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = async (e) => {
            try {
                const buffer = await audioContext.decodeAudioData(e.target.result);
                const pad = pads[selectedPadIndex];
                pad.sample = buffer;
                pad.sampleName = file.name;
                showMessage(`Sample "${file.name}" loaded to Pad ${selectedPadIndex + 1}`);
                updateUI();
            } catch (err) {
                showMessage("Error: Could not decode audio file.");
                console.error("Audio Decode Error:", err);
            }
        };
        reader.readAsArrayBuffer(file);
        sampleLoaderInput.value = ''; // Reset input
    }

    function saveProject() {
        const projectData = {
            tempo: tempo,
            swing: swing,
            pads: pads.map(p => ({...p, sample: null})) // Don't save the audio buffer directly
        };
        const blob = new Blob([JSON.stringify(projectData, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `quantizer-project-${new Date().toISOString().slice(0,10)}.json`;
        a.click();
        URL.revokeObjectURL(url);
        showMessage("Project Saved!");
    }

    function loadProject(event) {
        const file = event.target.files[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const projectData = JSON.parse(e.target.result);
                tempo = projectData.tempo || 120;
                swing = projectData.swing || 0;

                // Restore pad data, but keep existing samples
                projectData.pads.forEach((savedPad, i) => {
                    if(pads[i]) {
                       Object.assign(pads[i], { ...savedPad, sample: pads[i].sample });
                    }
                });

                tempoSlider.value = tempo;
                tempoDisplay.textContent = tempo;
                swingSlider.value = swing;
                swingDisplay.textContent = `${swing}%`;

                updateUI();
                showMessage(`Project "${file.name}" loaded.`);
            } catch (err) {
                showMessage("Error: Invalid project file.");
                console.error("Project Load Error:", err);
            }
        };
        reader.readAsJSON(file);
        loadProjectInput.value = '';
    }

    // --- AI & API INTEGRATION --- //

    async function handleAiPrompt() {
        if (checkApiKey() === false) { showMessage("AI Features disabled. Please set API Key."); return; }
        const prompt = aiPromptInput.value;
        if(!prompt) return;

        addChatMessage('user', prompt);
        aiPromptInput.value = '';
        aiLoader.style.display = 'block';

        try {
            if(prompt.toLowerCase().match(/beat|rhythm|pattern|sequence/)) {
                await getAIPattern(prompt, selectedPadIndex);
            } else {
                await getAISoundDesign(prompt, selectedPadIndex);
            }
        } catch (error) {
            console.error("AI Generation Error:", error);
            addChatMessage('assistant', `Sorry, I had trouble with that request. Error: ${error.message}`);
        } finally {
            aiLoader.style.display = 'none';
        }
    }

    function addChatMessage(role, text) {
        const msgDiv = document.createElement('div');
        msgDiv.className = `p-2 my-1 rounded-lg ${role === 'user' ? 'bg-primary-color bg-opacity-30 text-right' : 'bg-gray-700'}`;
        msgDiv.textContent = text;
        aiChatBox.appendChild(msgDiv);
        aiChatBox.scrollTop = aiChatBox.scrollHeight;
    }

    async function apiFetch(url, payload) {
        const response = await fetch(url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
        });
        if (!response.ok) {
            const error = await response.json();
            throw new Error(error.error.message || `API Error: ${response.status}`);
        }
        return response.json();
    }

    async function generateImage(prompt, padIndex) {
        if (checkApiKey() === false) { showMessage("AI Features disabled. Please set API Key."); return; }
        visualLoader.style.display = 'flex';
        try {
            const result = await apiFetch(`https://generativelanguage.googleapis.com/v1beta/models/imagen-3.0-generate-002:predict?key=${apiKey}`, { 
                instances: [{ prompt: prompt }],
                parameters: { "sampleCount": 1 }
            });
            if (result.predictions && result.predictions[0].bytesBase64Encoded) {
                const imageUrl = `data:image/png;base64,${result.predictions[0].bytesBase64Encoded}`;
                pads[padIndex].visualUrl = imageUrl;
                videoDisplay.innerHTML = `<img src="${imageUrl}" class="w-full h-full object-cover" alt="${prompt}">`;
            } else { throw new Error("No image data in API response."); }
        } catch (error) {
            console.error('Image Generation Error:', error);
            showMessage(`Image generation failed: ${error.message}`);
            videoDisplay.innerHTML = `<span class="text-red-500 p-4">Generation Failed</span>`;
        } finally {
            visualLoader.style.display = 'none';
        }
    }

    async function getAISoundDesign(prompt, padIndex, silent = false) {
        const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-05-20:generateContent?key=${apiKey}`;
        const systemPrompt = "You are a sound design assistant for a sampler. Generate parameters for the sound based on the user's description. Respond ONLY with a valid JSON object. Pitch is in semitones (-24 to 24). Filter cutoff is in Hz (20 to 20000). Filter resonance is 0.0 to 20.0. Attack and Release are in seconds (0.01 to 4.0).";
        const payload = {
            systemInstruction: { parts: [{ text: systemPrompt }] },
            contents: [{ parts: [{ text: prompt }] }],
            generationConfig: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: "OBJECT",
                    properties: {
                        pitch: { type: "NUMBER" }, filterCutoff: { type: "NUMBER" },
                        filterResonance: { type: "NUMBER" }, attack: { type: "NUMBER" }, release: { type: "NUMBER" }
                    },
                    required: ["pitch", "filterCutoff", "filterResonance", "attack", "release"]
                }
            }
        };

        const result = await apiFetch(apiUrl, payload);
        const params = JSON.parse(result.candidates[0].content.parts[0].text);

        const pad = pads[padIndex];
        pad.sample = baseSample; // Assign a base sound source to be shaped
        pad.sampleName = `AI: ${prompt.substring(0,20)}`;
        pad.pitch = Math.max(-24, Math.min(24, Math.round(params.pitch)));
        pad.filterCutoff = Math.max(20, Math.min(20000, Math.round(params.filterCutoff)));
        pad.filterResonance = Math.max(0, Math.min(20, parseFloat(params.filterResonance)));
        pad.attack = Math.max(0.01, Math.min(2, parseFloat(params.attack)));
        pad.release = Math.max(0.01, Math.min(4, parseFloat(params.release)));

        if (!silent) {
            addChatMessage('assistant', `OK, I've created a sound for you on Pad ${padIndex + 1}.`);
            updateUI();
        }
    }

    async function getAIPattern(prompt, padIndex, silent = false) {
        const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-05-20:generateContent?key=${apiKey}`;
        const systemPrompt = "You are a rhythm programming assistant. Generate a 16-step sequencer pattern as a JSON object with one key, 'pattern', which is an array of 16 booleans. `true` means the step is on. Respond ONLY with the valid JSON object.";
        const payload = {
            systemInstruction: { parts: [{ text: systemPrompt }] },
            contents: [{ parts: [{ text: prompt }] }],
            generationConfig: {
                responseMimeType: "application/json",
                responseSchema: { type: "OBJECT", properties: { pattern: { type: "ARRAY", items: { type: "BOOLEAN" }}}, required: ["pattern"] }
            }
        };

        const result = await apiFetch(apiUrl, payload);
        const data = JSON.parse(result.candidates[0].content.parts[0].text);

        if (data.pattern && data.pattern.length === 16) {
            pads[padIndex].pattern = data.pattern;
            if (!silent) {
                addChatMessage('assistant', `Done! I've programmed that rhythm onto Pad ${padIndex + 1}.`);
                updateSequencer();
            }
        } else { throw new Error("AI returned an invalid pattern format."); }
    }

    async function generateFullKit() {
        if (checkApiKey() === false) { showMessage("AI Features disabled. Please set API Key."); return; }
        const kitStyle = prompt("Describe the style of drum kit you want to generate:", "a punchy, classic hip-hop drum kit");
        if (!kitStyle) return;

        const padPrompts = [
            { padIndex: 0, soundPrompt: `a deep, punchy kick drum sound for ${kitStyle}`, patternPrompt: `a classic kick drum pattern for ${kitStyle}` },
            { padIndex: 1, soundPrompt: `a crisp, sharp snare drum sound for ${kitStyle}`, patternPrompt: `a classic snare pattern on the 2 and 4 for ${kitStyle}` },
            { padIndex: 2, soundPrompt: `a clean, closed hi-hat sound for ${kitStyle}`, patternPrompt: `a steady 16th note hi-hat pattern for ${kitStyle}` },
            { padIndex: 3, soundPrompt: `an open hi-hat sound that complements ${kitStyle}`, patternPrompt: `a simple open hi-hat pattern on the off-beats for ${kitStyle}` },
        ];

        loaderText.textContent = `Generating ${kitStyle}...`;
        fullScreenLoader.style.display = 'flex';

        try {
            await Promise.all(padPrompts.map(p => Promise.all([
                getAISoundDesign(p.soundPrompt, p.padIndex, true),
                getAIPattern(p.patternPrompt, p.padIndex, true)
            ])));

            updateUI();
            showMessage(`✨ New ${kitStyle} generated on pads 1-4!`);
            if (isTtsEnabled) speak("New kit generated.");

        } catch (error) {
            console.error("Generate Kit Error:", error);
            showMessage(`Failed to generate kit: ${error.message}`);
        } finally {
            fullScreenLoader.style.display = 'none';
        }
    }

    async function evolveCurrentPattern() {
        if (checkApiKey() === false) { showMessage("AI Features disabled. Please set API Key."); return; }
        const pad = pads[selectedPadIndex];
        const prompt = `Here is a 16-step musical pattern: ${JSON.stringify(pad.pattern)}. Create a related but slightly more complex or syncopated variation.`;

        loaderText.textContent = `Evolving Pattern for Pad ${selectedPadIndex + 1}...`;
        fullScreenLoader.style.display = 'flex';

        try {
            await getAIPattern(prompt, selectedPadIndex, true);
            updateSequencer();
            if(isTtsEnabled) speak("Pattern evolved.");
        } catch (error) {
            console.error("Evolve Pattern Error:", error);
            showMessage(`Failed to evolve pattern: ${error.message}`);
        } finally {
            fullScreenLoader.style.display = 'none';
        }
    }

    // --- UTILITY & HELPER FUNCTIONS --- //

    function showMessage(message, duration = 2500) {
        if (toastTimer) clearTimeout(toastTimer);
        toastText.textContent = message;
        toastNotification.style.opacity = 1;
        toastTimer = setTimeout(() => { toastNotification.style.opacity = 0; }, duration);
    }

    function createBaseSample() {
        if (!audioContext || baseSample) return;
        const frameCount = audioContext.sampleRate * 0.1;
        const buffer = audioContext.createBuffer(1, frameCount, audioContext.sampleRate);
        const data = buffer.getChannelData(0);
        for (let i = 0; i < frameCount; i++) {
            data[i] = Math.sin(i / frameCount * Math.PI * 8) * Math.exp(-i / frameCount * 8);
        }
        baseSample = buffer;
    }

    async function setupMicrophone() {
        try {
            micStream = await navigator.mediaDevices.getUserMedia({ audio: true });
            const source = audioContext.createMediaStreamSource(micStream);
            analyser = audioContext.createAnalyser();
            analyser.fftSize = 2048;
            source.connect(analyser);
            waveformData = new Uint8Array(analyser.frequencyBinCount);
            mediaRecorder = new MediaRecorder(micStream);

            mediaRecorder.ondataavailable = (event) => {
                if(event.data.size > 0 && isArmed) {
                    const padIndexToRecord = (currentStep - 1 + NUM_STEPS) % NUM_STEPS;
                    if (pads[padIndexToRecord].set === activeSetIndex) {
                        const reader = new FileReader();
                        reader.onload = () => {
                            audioContext.decodeAudioData(reader.result, (buffer) => {
                                pads[padIndexToRecord].sample = buffer;
                                pads[padIndexToRecord].sampleName = `Rec @ ${new Date().toLocaleTimeString()}`;
                                showMessage(`Sample recorded to Pad ${padIndexToRecord + 1}`);
                                updateUI();
                            });
                        };
                        reader.readAsArrayBuffer(event.data);
                    }
                }
            };
        } catch (err) {
            console.error('Mic Error:', err);
            showMessage('Mic access denied. Recording disabled.');
        }
    }

    function toggleTTS() {
        isTtsEnabled = !isTtsEnabled;
        ttsIconOn.classList.toggle('hidden');
        ttsIconOff.classList.toggle('hidden');
        if (audioContext) speak(`Voice feedback ${isTtsEnabled ? 'enabled' : 'disabled'}`);
    }

    async function speak(text) {
        if (!isTtsEnabled || !audioContext || audioContext.state !== 'running' || checkApiKey() === false) return;
        // This is a simplified TTS approach for brevity. The original complex conversion is also valid.
        try {
            const utterance = new SpeechSynthesisUtterance(text);
            speechSynthesis.speak(utterance);
        } catch (error) {
            console.error("TTS Failed:", error);
        }
    }

    // --- START THE APP --- //
    init();
});
</script>
</body>
</html>
